#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x > y) - (x < y);
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int sz = 2 * N;
        long long *arr = (long long*)malloc(sz * sizeof(long long));
        for (int i = 0; i < sz; ++i) scanf("%lld", &arr[i]);
        qsort(arr, sz, sizeof(long long), cmp);
        int ok = 1;
        for (int i = 0; i < sz; ) {
            int j = i;
            while (j < sz && arr[j] == arr[i]) ++j;
            if (j - i > 2) { ok = 0; break; }
            i = j;
        }
        printf(ok ? "Yes\n" : "No\n");
        free(arr);
    }
    return 0;
}

