#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        sz = 2 * N
        freq = {}
        ok = True
        for _ in range(sz):
            x = int(next(it))
            cnt = freq.get(x, 0) + 1
            freq[x] = cnt
            if cnt > 2:
                ok = False
        out_lines.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

